export const DrawerDemo = <Message = never>(
  controller: DrawerExampleController<Message> = {},
): Html => {
  const h = html<never>()

  return drawerShell(
    {
      id: 'drawer-demo',
      trigger: 'Open Drawer',
      title: 'Move Goal',
      description: 'Set your daily activity goal.',
      body: [
        h.div(
          [h.Class('mx-auto w-full max-w-sm')],
          [
            goalControls({
              caloriesPerDay: 'Calories/day',
              decrease: 'Decrease',
              goal: '350',
              increase: 'Increase',
            }),
          ],
        ),
      ],
      contentClassName: 'data-[vaul-drawer-direction=bottom]:!max-h-[25vh]',
      footer: footerButtons({ cancel: 'Cancel', submit: 'Submit' }),
    },
    controller,
  )
}

export const DrawerWithSides = <Message = never>(
  controller: DrawerExampleController<Message> = {},
): Html => {
  const localHtml = html<never>()

  return localHtml.div(
    [localHtml.Class('flex flex-wrap gap-2')],
    drawerDirections.map(direction =>
      drawerShell(
        {
          id: `drawer-${direction}`,
          trigger: direction,
          title: 'Move Goal',
          description: 'Set your daily activity goal.',
          direction,
          contentClassName:
            'data-[vaul-drawer-direction=bottom]:!max-h-[25vh] data-[vaul-drawer-direction=top]:!max-h-[25vh]',
          body: scrollableBody(),
          footer: footerButtons({ cancel: 'Cancel', submit: 'Submit' }),
        },
        controller,
      ),
    ),
  )
}

